  function bind(){ if(bind._ok) return; bind._ok=1;
    document.addEventListener('click', function(e){
      var t=e.target;
      if(t.closest('#chat-list-search-btn')){ var p=q('#chat-page'); if(p){ p.classList.toggle('search-open'); p.classList.remove('filter-open'); var s=q('#chat-search'); if(s&&p.classList.contains('search-open')) setTimeout(function(){s.focus();},20); } }
      else if(t.closest('#chat-list-filter-btn')){ var p2=q('#chat-page'); if(p2){ p2.classList.toggle('filter-open'); p2.classList.remove('search-open'); } }
      else if(t.closest('[data-bx-create]')){ var a=t.closest('[data-bx-create]').getAttribute('data-bx-create'); if(a==='group'&&typeof openNew==='function'){ closeM('mo-chat-create'); openNew('group'); } else if(a==='copilot'){ toast('Atalho visual do CoPilot aplicado ao main pager.'); } else { toast('Estrutura visual aplicada — fluxo funcional pode ser ligado depois sem reescrever o chat.'); } }
      else if(t.closest('[data-bx-rx]')){ var b=t.closest('[data-bx-rx]'); closeM('mo-chat-msg-sheet'); if(typeof v4ToggleRx==='function') v4ToggleRx(b.getAttribute('data-bx-msg'), b.getAttribute('data-bx-rx')); }
      else if(t.closest('[data-bx-msg-action]')){ var b2=t.closest('[data-bx-msg-action]'), a2=b2.getAttribute('data-bx-msg-action'), id=b2.getAttribute('data-bx-msg'); closeM('mo-chat-msg-sheet'); if(a2==='copilot'){ toast('Entrada “Pergunte ao CoPilot” espelhada visualmente.'); return; } if(a2==='task'){ createTaskFromMessage(id); return; } if(a2==='other'){ if(window._legacyOpenMsgMenu){ _legacyOpenMsgMenu({clientX:window.innerWidth/2,clientY:window.innerHeight*0.55}, id); } return; } if(typeof runMsgAction==='function'){ runMsgAction(a2,id); if(a2==='forward') setTimeout(refineForwardModal,30); } }
      else if(t.closest('#chat-inspect-back')){ closeM('mo-chat-inspect'); }
      else if(t.closest('[data-bx-inspect-action]')){ var ac=t.closest('[data-bx-inspect-action]').getAttribute('data-bx-inspect-action'), r=typeof activeRoom==='function'?activeRoom():null, u=directUser(r), tel=phoneRaw(u); if(ac==='call'&&tel&&typeof callClient==='function'){ callClient(tel,u&&u.nome||''); } else if(ac==='video'&&tel&&typeof openWhatsApp==='function'){ openWhatsApp(tel,u&&u.nome||''); } else if(ac==='search'){ closeM('mo-chat-inspect'); var s2=q('#chat-page'); if(s2){ s2.classList.add('search-open'); var inp=q('#chat-search'); if(inp) setTimeout(function(){inp.focus();},20); } } else if(ac==='audio'){ if(window.C) C._detailTab='audio'; if(typeof _chatRenderInspect==='function') _chatRenderInspect(); } }
    }, true);
    document.addEventListener('input', function(e){ if(e.target&&e.target.id==='chat-text') syncComposer(); if(e.target&&e.target.id==='chat-forward-search'){ var val=String(e.target.value||'').toLowerCase(); qa('#chat-forward-list [data-fwd-room]').forEach(function(btn){btn.style.display=String(btn.textContent||'').toLowerCase().indexOf(val)>=0?'':'none';}); } }, true);
  }
