    if(typeof renderRooms==='function' && !renderRooms._refine2026){ var rr=renderRooms; window.renderRooms=function(){ var out=rr.apply(this,arguments); refineHeader(); refineCreateSheet(); refineTopBar(); syncUnreadBadge(); refineForwardModal(); syncComposer(); return out; }; window.renderRooms._refine2026=1; }
    if(typeof renderHeader==='function' && !renderHeader._refine2026){ var rh=renderHeader; window.renderHeader=function(){ var out=rh.apply(this,arguments); refineHeader(); refineTopBar(); syncComposer(); return out; }; window.renderHeader._refine2026=1; }
    if(typeof renderComposer==='function' && !renderComposer._refine2026){ var rc=renderComposer; window.renderComposer=function(){ var out=rc.apply(this,arguments); syncComposer(); return out; }; window.renderComposer._refine2026=1; }
